import { unstable_cache } from "next/cache";
import { revalidateTag } from "next/cache";
import { getAllProducts } from "@/lib/db";

/* ------------------------------------------------------------------ */
/*  Cached product fetcher                                            */
/*                                                                     */
/*  The `"products"` cache tag is used consistently so that a single   */
/*  revalidation call (via syncCatalog) refreshes every view that      */
/*  depends on catalog data.                                           */
/* ------------------------------------------------------------------ */
const getCachedProducts = unstable_cache(
  async () => {
    const products = await getAllProducts();
    return {
      products,
      fetchedAt: new Date().toISOString(),
    };
  },
  ["admin-products"],
  {
    tags: ["products"],
    /** Keep the cache forever unless explicitly invalidated — the
     *  admin's "Sync latest catalog" action is the only thing that
     *  should trigger a refresh.                                           */
    revalidate: false,
  }
);

/* ------------------------------------------------------------------ */
/*  Sync Server Action (inline)                                        */
/*                                                                     */
/*  Invalidate all cached data tagged `"products"`, then return        */
/*  immediately — the product list may be stale for a moment while     */
/*  fresh data is fetched on the next page render.                     */
/*                                                                     */
/*  In a production system this is where you'd also enqueue an         */
/*  ERP/PIM import job (e.g. write to a Bull/SQS queue) that runs     */
/*  asynchronously and calls revalidateTag("products") when finished.  */
/* ------------------------------------------------------------------ */
async function syncCatalog(formData: FormData) {
  "use server";

  // ── Optionally kick off a background sync job here ──────────────
  //   e.g.:  await queue.enqueue("catalog:sync-import");
  //   ─ or ─ start a long-lived process and return immediately:
  //   void triggerCatalogImport().then(() => revalidateTag("products"));

  revalidateTag("products");
}

/* ------------------------------------------------------------------ */
/*  Page                                                               */
/* ------------------------------------------------------------------ */
export default async function AdminProductsPage() {
  const { products, fetchedAt } = await getCachedProducts();

  return (
    <div>
      <section
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "baseline",
          marginBottom: "1.25rem",
        }}
      >
        <div>
          <h2 style={{ margin: 0, fontSize: "1.25rem" }}>Product Catalog</h2>
          <p
            style={{
              margin: "0.25rem 0 0",
              fontSize: "0.8rem",
              color: "#666",
            }}
          >
            Cached at&ensp;
            <time dateTime={fetchedAt}>
              {new Date(fetchedAt).toLocaleString()}
            </time>
          </p>
        </div>

        <form action={syncCatalog}>
          <button
            type="submit"
            style={{
              padding: "0.5rem 1rem",
              fontSize: "0.875rem",
              cursor: "pointer",
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </section>

      <div style={{ overflowX: "auto" }}>
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            fontSize: "0.9rem",
          }}
        >
          <thead>
            <tr style={{ borderBottom: "2px solid #ccc" }}>
              <th
                style={{
                  textAlign: "left",
                  padding: "0.5rem 0.75rem",
                  fontWeight: 600,
                }}
              >
                SKU
              </th>
              <th
                style={{
                  textAlign: "left",
                  padding: "0.5rem 0.75rem",
                  fontWeight: 600,
                }}
              >
                Name
              </th>
              <th
                style={{
                  textAlign: "right",
                  padding: "0.5rem 0.75rem",
                  fontWeight: 600,
                }}
              >
                Price
              </th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: "1px solid #e0e0e0" }}
              >
                <td style={{ padding: "0.5rem 0.75rem", color: "#555" }}>
                  #{product.id}
                </td>
                <td style={{ padding: "0.5rem 0.75rem" }}>{product.name}</td>
                <td style={{ padding: "0.5rem 0.75rem", textAlign: "right" }}>
                  ${product.price}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <p
        style={{
          marginTop: "1rem",
          fontSize: "0.8rem",
          color: "#666",
        }}
      >
        {products.length} product{products.length === 1 ? "" : "s"} listed.
        &nbsp; Data is cached until &ldquo;Sync latest catalog&rdquo; is
        triggered.
      </p>
    </div>
  );
}

